function SearchComponent() {
  const [query, setQuery] = React.useState('');

  return (
    <DelayedTextInput
      value={query}
      onUpdate={setQuery}
      delay={300}
      hasClear
      placeholder="Search..."
    />
  );
}

function MediaButton({ images }) {
  const { openGallery } = useGallery();
  return (
    <Button onClick={() => openGallery(images, 0)}>
      View Images
    </Button>
  );
}

const {data, fetchNextPage} = useFeedQuery();
const allLoaded = data.items.length >= data.total;

<InfiniteScroll onActivate={fetchNextPage} disabled={allLoaded}>
  {data.items.map((item) => (
    <FeedItem key={item.id} item={item} />
  ))}
</InfiniteScroll>
